# ── Chargement modèle ─────────────────────────────────────────────
@st.cache_resource
def load_model():
    modele   = joblib.load(ROOT / "models/modele_niveau1_final.pkl")
    encodeur = joblib.load(ROOT / "models/encodeur_equipes.pkl")
    enc_y    = joblib.load(ROOT / "models/encodeur_cible.pkl")
    ranking  = pd.read_csv(ROOT / "data/ranking_2026.csv")
    # Ajouter Cape Verde manuellement
    cape_verde = pd.DataFrame([{'team': 'Cape Verde', 'fifa_points': 1400.0}])
    ranking = pd.concat([ranking, cape_verde], ignore_index=True)
    return modele, encodeur, enc_y, ranking

modele, encodeur, enc_y, ranking = load_model()

