equipes = sorted(set([t for teams in GROUPES.values() for t in teams]))

def predire_match(home, away):
    home_pts = ranking[ranking['team'] == home]['fifa_points'].values
    away_pts = ranking[ranking['team'] == away]['fifa_points'].values
    home_pts = float(home_pts[0]) if len(home_pts) > 0 else 1552.0
    away_pts = float(away_pts[0]) if len(away_pts) > 0 else 1552.0
    all_teams = list(encodeur.classes_)
    home_enc = all_teams.index(home) if home in all_teams else 0
    away_enc = all_teams.index(away) if away in all_teams else 0
    X = pd.DataFrame([[home_enc, away_enc, home_pts, away_pts, 0.5, 0.5, 1.8, 1.4, 1.2, 1.1, 0.5]],
        columns=['home_team_enc','away_team_enc','home_fifa_points','away_fifa_points',
                 'home_forme','away_forme','moy_buts_marques_home','moy_buts_marques_away',
                 'moy_buts_encaisses_home','moy_buts_encaisses_away','h2h'])
    proba = modele.predict_proba(X)[0]
    return dict(zip(enc_y.classes_, proba))

