            cc1.metric(f"Victoire {t1}", f"{v:.1%}")
            cc2.metric("Match Nul",      f"{n:.1%}")
            cc3.metric(f"Victoire {t2}", f"{d:.1%}")
            if v > d:   st.success(f"🏆 Favori : {t1}")
            elif d > v: st.success(f"🏆 Favori : {t2}")
            else:       st.warning("🤝 Match très équilibré !")
